+/// Extract a required string field from input.
+fn require_str<'a>(input: &'a serde_json::Value, field: &str) -> Result<&'a str, SentryError> {
+    input
+        .get(field)
+        .and_then(|v| v.as_str())
+        .ok_or_else(|| SentryError::Api {
+            status_code: 400,
+            message: format!("Missing required field: {field}"),
+        })
+}
